import torch  # 方法1：直接检查CUDA是否可用 print(f"PyTorch版本: {torch.__version__}") print(f"CUDA是否可用: {torch.cuda.is_available()}")  # 如果可用，显示更多信息 if torch.cuda.is_available():     print(f"当前CUDA设备: {torch.cuda.current_device()}")     print(f"设备名称: {torch.cuda.get_device_name(torch.cuda.current_device())}")     print(f"设备数量: {torch.cuda.device_count()}")      # 显示每个设备的信息     for i in range(torch.cuda.device_count()):         print(f"\n设备 {i}:")         print(f"  名称: {torch.cuda.get_device_name(i)}")         print(f"  内存总量: {torch.cuda.get_device_properties(i).total_memory / 1024 ** 3:.2f} GB")         print(f"  计算能力: {torch.cuda.get_device_capability(i)}") else:     print("CUDA不可用。请检查:")     print("1. 是否安装了NVIDIA显卡驱动")     print("2. 是否安装了支持CUDA的PyTorch版本")     print("3. PyTorch版本是否与CUDA版本匹配")
